	public void getCutOffDt()
	{
		String function_nm="getCutOffDt()";
		try
		{
			if(!report_dt.equals(""))
			{
				//String sysdate=dateUtil.getSysdate();
				//String report_year=sysdate.substring(6);
				String report_year=report_dt.substring(6);
				cutoff_dt=dateUtil.getFirstDateOfYear(report_year);
			}
		}
		catch(Exception e)
		{
			new SystemErrorLogger().InsertErrorLogger(db_src_file_name, function_nm, e);
		}
	}
	
	public void getCompanyList()
	{
		String function_nm="getCompanyList()";
		try
		{
			String query="SELECT DISTINCT COMPANY_CD "
					+ "FROM FMS_COMPANY_OWNER_MST A "
					+ "WHERE EFF_DT=(SELECT MAX(B.EFF_DT) FROM "
					+ "FMS_COMPANY_OWNER_MST B WHERE A.COMPANY_CD=B.COMPANY_CD) ";
			stmt=conn.prepareStatement(query);
			rset=stmt.executeQuery();
			while(rset.next())
			{
				String company_cd = rset.getString(1)==null?"":rset.getString(1);
				
				VMST_COMPANY_CD.add(company_cd);
				VMST_COMPANY_ABBR.add(""+utilBean.getCompanyAbbr(conn, company_cd));
				VMST_COMPANY_NM.add(""+utilBean.getCompanyName(conn, company_cd));
			}
			rset.close();
			stmt.close();
		}
		catch(Exception e)
		{
			new SystemErrorLogger().InsertErrorLogger(db_src_file_name, function_nm, e);
		}
	}
	
