				String cont_ref=rset.getString(10)==null?"":rset.getString(10);
				String rate=rset.getString(11)==null?"":nf.format(rset.getDouble(11));
				String rate_unit=rset.getString(12)==null?"":rset.getString(12);
				String cargo_no=rset.getString(13)==null?"":rset.getString(13);
				String act_recpt_dt=rset.getString(14)==null?"":rset.getString(14);
				String storage_end_dt=rset.getString(15)==null?"":rset.getString(15);
				String bu_seq=rset.getString(16)==null?"":rset.getString(16);
				String plant_seq=rset.getString(17)==null?"":rset.getString(17);
				String dcq=rset.getString(18)==null?"":rset.getString(18);
				String agmt_base=rset.getString(19)==null?"":rset.getString(19);
				
				VTEMP_COUNTERPARTY_CD.add(counterparty_cd);
				VTEMP_AGMT_NO.add(agmt_no);
				VTEMP_AGMT_REV.add(agmt_rev);
				VTEMP_CONT_NO.add(cont_no);
				VTEMP_CONT_REV.add(cont_rev);
				VTEMP_CONT_TYPE.add(cont_type);
				VTEMP_CONT_START_DT.add(act_recpt_dt);
				VTEMP_CONT_END_DT.add(storage_end_dt);
				VTEMP_AGMT_BASE.add(agmt_base);
				VTEMP_BU_SEQ.add(bu_seq);
				VTEMP_PLANT_SEQ.add(plant_seq);
				VTEMP_RATE.add(rate);
