	//PB20260204: FOR SALES FETCHING THE ACCRUAL DETAILS FROM THE EOD
	//LATEST EOD data are shown in the report
	public void getSalesEODdetail()
	{
		String function_nm="getSalesEODdetail()";
		try
		{
			String rpt_dt="";
			String query="SELECT COMPANY_CD,TO_CHAR(REPORT_DT,'DD/MM/YYYY'),FINANCIAL_YEAR,COUNTERPARTY_CD,AGMT_NO,AGMT_REV, "
					+ "CONT_NO,CONT_REV,CONTRACT_TYPE,AGMT_BASE,CARGO_NO,BU_UNIT,BU_STATE_TIN,PLANT_SEQ,TO_CHAR(INVOICE_DUE_DT,'DD/MM/YYYY'), "
					+ "FREQ,TO_CHAR(PERIOD_START_DT,'DD/MM/YYYY'),TO_CHAR(PERIOD_END_DT,'DD/MM/YYYY'),ACCRUAL_QTY,ACCRUAL_AMT, "
					+ "RATE_IN,INVOICE_RAISED_IN,GROSS_AMT,CONT_REF_NO,CASH_FLOW,TO_CHAR(CONT_START_DT,'DD/MM/YYYY'),TO_CHAR(CONT_END_DT,'DD/MM/YYYY') "
					+ "FROM FMS_ACCRUAL_DTL A "
					+ "WHERE COMPANY_CD=? AND REPORT_DT=TO_DATE(?,'DD/MM/YYYY') ";
			stmt=conn.prepareStatement(query);
			stmt.setString(1, comp_cd);
			stmt.setString(2, eff_accrual_dt);
			rset=stmt.executeQuery();
			while(rset.next())
			{
				String own_cd=rset.getString(1)==null?"":rset.getString(1);
				rpt_dt=rset.getString(2)==null?"":rset.getString(2);
				String fin_year=rset.getString(3)==null?"":rset.getString(3);
				String countpty_cd=rset.getString(4)==null?"":rset.getString(4);
				String agmt=rset.getString(5)==null?"":rset.getString(5);
				String agmt_rev=rset.getString(6)==null?"":rset.getString(6);
				String cont=rset.getString(7)==null?"":rset.getString(7);
				String cont_rev=rset.getString(8)==null?"":rset.getString(8);
				String cont_type=rset.getString(9)==null?"":rset.getString(9);
				String agmt_base=rset.getString(10)==null?"":rset.getString(10);
				String cargo_no=rset.getString(11)==null?"":rset.getString(11);
				String bu_seq=rset.getString(12)==null?"":rset.getString(12);
				String bu_state_tin=rset.getString(13)==null?"":rset.getString(13);
				String plant_seq=rset.getString(14)==null?"":rset.getString(14);
				String inv_due_dt=rset.getString(15)==null?"":rset.getString(15);
				String freq=rset.getString(16)==null?"":rset.getString(16);
				String periodStartDt=rset.getString(17)==null?"":rset.getString(17);
				String periodEndDt=rset.getString(18)==null?"":rset.getString(18);
				String accrual_qty=nf.format(rset.getDouble(19));
				String accrual_amt=nf.format(rset.getDouble(20));
				String rate_unit=rset.getString(21)==null?"":rset.getString(21);
				String inv_raised_in=rset.getString(22)==null?"":rset.getString(22);
				String gross_amt=nf.format(rset.getDouble(23));
				String ref_no=rset.getString(24)==null?"":rset.getString(24);
				String cash_flow=rset.getString(25)==null?"":rset.getString(25);
				String cont_start_dt=rset.getString(26)==null?"":rset.getString(26);
				String cont_end_dt=rset.getString(27)==null?"":rset.getString(27);

				comp_index_count+=1;
				
				VCOMPANY_CD.add(own_cd);
				VCOMPANY_ABBR.add(""+utilBean.getCompanyAbbr(conn, own_cd));
				VCOMPANY_NM.add(""+utilBean.getCompanyName(conn, own_cd));
				VCOUNTERPARTY_CD.add(countpty_cd);
				VCOUNTERPARTY_ABBR.add(""+utilBean.getCounterpartyABBR(conn, countpty_cd));
				VCOUNTERPARTY_NM.add(""+utilBean.getCounterpartyName(conn, countpty_cd));
				VAGMT_NO.add(agmt);
				VAGMT_REV.add(agmt_rev);
				VCONT_NO.add(cont);
				VCONT_REV.add(cont_rev);
				VCONTRACT_TYPE.add(cont_type);
				
				String deal_map = utilBean.NewDealMappingId(comp_cd, countpty_cd, agmt, agmt_rev,cont, cont_rev, cont_type,cargo_no);
				if(agmt_base.equals("D"))
				{
					deal_map+="<font style='background: #a6ff4d;'>[DLV]</font>";
				}
				VDISPLAY_DEAL_MAP.add(deal_map);
				VCONT_REF.add(ref_no);
				String cashflow=cash_flow+" [RLNG]";
				VINVOICE_TYPE.add(cashflow);	//cashflow type 
				VBILLING_FREQ_FLAG.add(freq);
				VBILLING_FREQ_NM.add(""+utilBean.getBillingFreqNm(freq));
				VPERIOD_START_DT.add(periodStartDt);
				VPERIOD_END_DT.add(periodEndDt);
				VINVOICE_DT.add(periodEndDt);
				VINVOICE_DUE_DT.add(inv_due_dt);
				VACC_COLOR.add("R");		//for tentative color R->Red
				//PB20250128: AS UNSETTLED REPORT SHOULD SHOW INR VALUES
				VSETTELED_AMT.add(gross_amt);
				VSETTELED_CURR.add("INR");
				VDEAL_TYPE.add("Sell");
				VCONT_START_DT.add(cont_start_dt);
				VCONT_END_DT.add(cont_end_dt);
				VPLANT_SEQ_NO.add(plant_seq);
				VBU_SEQ_NO.add(bu_seq);
				VPLANT_ABBR.add(""+utilBean.getCounterpartyPlantABBR(conn, countpty_cd, comp_cd, plant_seq, "C"));
				VBU_ABBR.add(""+utilBean.getCounterpartyPlantABBR(conn, comp_cd, comp_cd, bu_seq, "B"));
				VDOC_STATUS.add("Not Prepared");
				VOPS_FLAG.add("");
				VCARGO_NO.add(cargo_no);
				VINV_FLAG.add("");
				VSPLIT_FLAG.add("");
				VSPLIT_VAL.add("");
				VBOE_NO.add("");
				VBOE_NM.add("");
				VREPORT_DT.add(rpt_dt);
				String next_step=getNextStep("","","","","","","","","","","","","","");
				VNEXT_STEP.add(next_step);
				VINVOICE_NO.add("");
			}
			rset.close();
			stmt.close();
			
			SALES_ACCRUAL_DT.put(comp_cd, rpt_dt);
		}
		catch(Exception e)
		{
			new SystemErrorLogger().InsertErrorLogger(db_src_file_name, function_nm, e);
		}
	}
	
