						rset4=stmt4.executeQuery();
						if(rset4.next())
						{
							pdf_signed_flag=rset4.getString(1)==null?"":rset4.getString(1);
							email_sent_flag=rset4.getString(2)==null?"":rset4.getString(2);
							email_sent_dt=rset4.getString(3)==null?"":rset4.getString(3);
						}
						rset4.close();
						stmt4.close();
						
						if(!email_sent_flag.equals("") && sap_approval.equals("Y"))
						{
							/*
							getDays(String date, String date1)
							date>date1		>1
							date==date1		=1
							date<date1		<=0
						
							 */
							int count_days=dateUtil.getDays(email_sent_dt, report_dt);
							if(count_days<1)
							{
								continue;
							}
						}
						
						comp_index_count+=1;
						
						VCOMPANY_CD.add(comp_cd);
						VCOMPANY_ABBR.add(""+utilBean.getCompanyAbbr(conn, comp_cd));
						VCOMPANY_NM.add(""+utilBean.getCompanyName(conn, comp_cd));
						VCOUNTERPARTY_CD.add(""+VTEMP_COUNTERPARTY_CD.elementAt(i));
