						VCOUNTERPARTY_NM.add(""+utilBean.getCounterpartyName(conn, ""+VTEMP_COUNTERPARTY_CD.elementAt(i)));
						VAGMT_NO.add(""+VTEMP_AGMT_NO.elementAt(i));
						VAGMT_REV.add(""+VTEMP_AGMT_REV.elementAt(i));
						VCONT_NO.add(""+VTEMP_CONT_NO.elementAt(i));
						VCONT_REV.add(""+VTEMP_CONT_REV.elementAt(i));
						VCONTRACT_TYPE.add(""+VTEMP_CONT_TYPE.elementAt(i));
						
						String deal_map = utilBean.NewDealMappingId(comp_cd, ""+VTEMP_COUNTERPARTY_CD.elementAt(i), ""+VTEMP_AGMT_NO.elementAt(i), ""+VTEMP_AGMT_REV.elementAt(i),
								""+VTEMP_CONT_NO.elementAt(i), ""+VTEMP_CONT_REV.elementAt(i), ""+VTEMP_CONT_TYPE.elementAt(i), ""+VTEMP_CARGO_NO.elementAt(i));
						
