	public String getSvcContDtl(String company_cd, String counterparty_cd, String entity_type, String cont_no,String cont_type)
	{
		String function_nm="getSvcContDtl()";
		String map="";
		try
		{
			String query="SELECT CONT_REF_NO,TO_CHAR(START_DT,'DD/MM/YYYY'),TO_CHAR(END_DT,'DD/MM/YYYY') FROM FMS_CARGO_SVC_CONT_MST "
					+ "WHERE COMPANY_CD=? AND COUNTERPARTY_CD=? AND ENTITY_TYPE=? "
					+ "AND CONT_NO=? AND CONTRACT_TYPE=? ";
			stmt6=conn.prepareStatement(query);
			stmt6.setString(1, company_cd);
			stmt6.setString(2, counterparty_cd);
			stmt6.setString(3, entity_type);
			stmt6.setString(4, cont_no);
			stmt6.setString(5, cont_type);
			rset6=stmt6.executeQuery();
			if(rset6.next())
			{
				String ref=rset6.getString(1)==null?"":rset6.getString(1);
				String cont_st_dt=rset6.getString(2)==null?"":rset6.getString(2);
				String cont_end_dt=rset6.getString(3)==null?"":rset6.getString(3);
				
				map=ref+"@@"+cont_st_dt+"@@"+cont_end_dt;
			}
			rset6.close();
			stmt6.close();
		}
		catch(Exception e)
		{
			new SystemErrorLogger().InsertErrorLogger(db_src_file_name, function_nm, e);
		}
		return map;
	}
	
	public String getSVCPlantSeq(String company_cd,String counterparty_cd,String entity_type,String cont_no,String cont_type)
	{
		String function_nm="getSVCPlantSeq()";
		String seq_no="";
		try
		{
			String query="SELECT PLANT_SEQ_NO "
					+ "FROM FMS_CARGO_SVC_CONT_SVC_BU "
					+ "WHERE COMPANY_CD=? AND COUNTERPARTY_CD=? "
					+ "AND ENTITY_TYPE=? AND CONT_NO=? AND CONTRACT_TYPE=? ";
			stmt6=conn.prepareStatement(query);
			stmt6.setString(1, company_cd);
			stmt6.setString(2, counterparty_cd);
			stmt6.setString(3, entity_type);
			stmt6.setString(4, cont_no);
			stmt6.setString(5, cont_type);
			rset6=stmt6.executeQuery();
			if(rset6.next())
			{
				seq_no=rset6.getString(1)==null?"":rset6.getString(1);
			}
			rset6.close();
			stmt6.close();
		}
		catch(Exception e)
		{
			new SystemErrorLogger().InsertErrorLogger(db_src_file_name, function_nm, e);
		}
		return seq_no;
	}

