										VBU_ABBR.add(""+utilBean.getCounterpartyPlantABBR(conn, comp_cd, comp_cd, ""+VTEMP_BU_SEQ.elementAt(i), "B"));
										String doc_status=getDocStatus("",""+VTEMP_CONT_TYPE.elementAt(i),chk_flag,auth_flag,approve_flag,pdfInvDtl,sap_approval,fin_sys,pdf_signed_flag,email_sent_flag,email_sent_dt,sap_approved_dt);
										VDOC_STATUS.add(doc_status);
