	//function for fetching service contract details for DLNG
	public String getDlngSvcContDetails(String company_cd, String counterparty_cd, String agmt, String agmt_rev, String cont,String cont_type)
	{
		String function_nm="getDlngSvcContDetails()";
		String detail="";
		try
		{
			String queryString="SELECT CONT_REF_NO, TO_CHAR(START_DT,'DD/MM/YYYY'),TO_CHAR(END_DT,'DD/MM/YYYY') "
					+ "FROM FMS_SVC_CONT_MST A "
					+ "WHERE COMPANY_CD=? AND COUNTERPARTY_CD=? AND AGMT_NO=? AND AGMT_REV=? AND CONT_NO=? AND CONTRACT_TYPE=? "
					+ "AND CONT_REV=(SELECT MAX(CONT_REV) FROM FMS_SVC_CONT_MST B WHERE A.COMPANY_CD=B.COMPANY_CD "
					+ "AND A.COUNTERPARTY_CD=B.COUNTERPARTY_CD AND A.CONT_NO=B.CONT_NO AND A.CONTRACT_TYPE=B.CONTRACT_TYPE AND A.AGMT_NO=B.AGMT_NO "
					+ "AND A.AGMT_REV=B.AGMT_REV) ";
			stmt6=conn.prepareStatement(queryString);
			stmt6.setString(1, company_cd);
			stmt6.setString(2, counterparty_cd);
			stmt6.setString(3, agmt);
			stmt6.setString(4, agmt_rev);
			stmt6.setString(5, cont);
			stmt6.setString(6, cont_type);
			rset6=stmt6.executeQuery();
			if(rset6.next())
			{
				String cont_ref=rset6.getString(1)==null?"":rset6.getString(1);
				String start_dt=rset6.getString(2)==null?"":rset6.getString(2);
				String end_dt=rset6.getString(3)==null?"":rset6.getString(3);
				
				detail=cont_ref+"@@"+start_dt+"@@"+end_dt;
			}
			rset6.close();
			stmt6.close();
		}
		catch(Exception e)
		{
			new SystemErrorLogger().InsertErrorLogger(db_src_file_name, function_nm, e);
		}
		return detail;
	}
	
