				String cont_start_dt=rset.getString(19)==null?"":rset.getString(19);
				String cont_end_dt=rset.getString(20)==null?"":rset.getString(20);
				String gx_counterparty_cd=rset.getString(21)==null?"":rset.getString(21);
				String gx_bu_unit=rset.getString(22)==null?"":rset.getString(22);
				
				String gx_bu_plant_abbr=utilBean.getCounterpartyBuPlantABBR(conn,gx_counterparty_cd, comp_cd, gx_bu_unit, "G");

				comp_index_count+=1;
				
