	//FOR FINDING THE MAXEFFECTYIVE DATE FOR ACRUAL REPORT
	public void getEffectiveAccrualDt()
	{
		String function_nm="getEffectiveAccrualDt()";
		try
		{
			String query="SELECT TO_CHAR(MAX(EFF_REPORT_DT),'DD/MM/YYYY') "
					+ "FROM "
					+ "(SELECT MAX(REPORT_DT) EFF_REPORT_DT "
					+ "FROM FMS_ACCRUAL_DTL A  "
					+ "WHERE (REPORT_DT=TO_DATE(?,'DD/MM/YYYY') OR REPORT_DT=(TO_DATE(?,'DD/MM/YYYY')-1)) "
					+ "UNION "
					+ "SELECT MAX(REPORT_DT) EFF_REPORT_DT "
					+ "FROM  FMS_TRADER_ACCRUAL_DTL A  "
					+ "WHERE (REPORT_DT=TO_DATE(?,'DD/MM/YYYY') OR REPORT_DT=(TO_DATE(?,'DD/MM/YYYY')-1)) "
					+ "UNION "
					+ "SELECT  MAX(REPORT_DT) EFF_REPORT_DT "
					+ "FROM FMS_GTA_ACCRUAL_DTL A  "
					+ "WHERE (REPORT_DT=TO_DATE(?,'DD/MM/YYYY') OR REPORT_DT=(TO_DATE(?,'DD/MM/YYYY')-1)) "
					+ "UNION "
					+ "SELECT  MAX(REPORT_DT) EFF_REPORT_DT "
					+ "FROM FMS_GX_ACCRUAL_DTL A  "
					+ "WHERE (REPORT_DT=TO_DATE(?,'DD/MM/YYYY') OR REPORT_DT=(TO_DATE(?,'DD/MM/YYYY')-1)) "
					+ "UNION "
					+ "SELECT  MAX(REPORT_DT) EFF_REPORT_DT "
					+ "FROM FMS_DERV_ACCRUAL_DTL A  "
					+ "WHERE  (REPORT_DT=TO_DATE(?,'DD/MM/YYYY') OR REPORT_DT=(TO_DATE(?,'DD/MM/YYYY')-1)) AND IS_MTM='N') ";
			stmt=conn.prepareStatement(query);
			int count=0;
			stmt.setString(++count, report_dt);
			stmt.setString(++count, report_dt);
			stmt.setString(++count, report_dt);
			stmt.setString(++count, report_dt);
			stmt.setString(++count, report_dt);
			stmt.setString(++count, report_dt);
			stmt.setString(++count, report_dt);
			stmt.setString(++count, report_dt);
			stmt.setString(++count, report_dt);
			stmt.setString(++count, report_dt);
			rset=stmt.executeQuery();
			if(rset.next())
			{
				eff_accrual_dt=rset.getString(1)==null?"":rset.getString(1);
			}
			rset.close();
			stmt.close();
		}
		catch(Exception e)
		{
			new SystemErrorLogger().InsertErrorLogger(db_src_file_name, function_nm, e);
		}
	}
	
	//PB20260402: for finding the next step for invoice preparation 
	public String getNextStep(String gx,String status, String cont_type, String chk_flag, String auth_flag, String approve_flag, String pdfInvDtl, String sap_approval_flag, String fin_sys, 
			String pdf_sign_flag, String email_sent_flag, String irn_flag, String upld_inv, String inv_type)
	{
		String function_nm="getNextStep()";
		String nextStep="";
		try
		{
			if(status.equalsIgnoreCase("Prepared"))
			{
				nextStep="IRP Check";
			}
			if(!status.equals(""))
			{
				//for gx invoice
				if(!gx.equals(""))
				{
					if(cont_type.equals("X")||cont_type.equals("W"))
					{
						cont_type="I";
					}
				}
				
				if(cont_type.equals("D")||cont_type.equals("T")||cont_type.equals("I")||cont_type.equals("P")||cont_type.equals("N")||cont_type.equals("G")
						||cont_type.equals("A")||cont_type.equals("H")||cont_type.equals("Y") ||cont_type.equals("C")||cont_type.equals("K")||cont_type.equals("R"))
				{
					if(chk_flag.equals("Y"))
					{
						nextStep="IRP Approval";
					}
					if(auth_flag.equals("Y"))
					{
						nextStep="Fin Ops Finalization";
					}
					if(approve_flag.equals("A"))
					{
						nextStep="Print PDF";
					}
					if(!pdfInvDtl.equals(""))
					{
						nextStep="SAP/SUN Approval";
						//nextStep="Upload Received Invoice";
					}
					if(sap_approval_flag.equals("Y"))
					{
						nextStep="";
					}
					/*if(upld_inv.equals("Y"))
					{
						nextStep="Send Mail";
					}*/
				}
				else if(cont_type.equals("S")||cont_type.equals("L")||cont_type.equals("X")||cont_type.equals("O")||cont_type.equals("Q")
						||cont_type.equals("F")||cont_type.equals("E")||cont_type.equals("W")||cont_type.equals("B")||cont_type.equals("M")||cont_type.equals("V"))
				{
					if(chk_flag.equals("Y"))
					{
						nextStep="Fin Ops Finalization";
					}
					if(approve_flag.equals("Y"))
					{
						if(cont_type.equals("O")||cont_type.equals("Q")||cont_type.equals("B")||cont_type.equals("M"))
						{
							nextStep="IRN Generation";
							if(irn_flag.equals("Y"))
							{
								nextStep="Print PDF";
							}
						}
						else 
						{
							nextStep="Print PDF";
						}
					}
					
					if(!pdfInvDtl.equals(""))
					{
						if(inv_type.equals("R"))
						{
							//nextStep="Upload Received Invoice";
							nextStep="SAP/SUN Approval";
						}
						else
						{
							nextStep="Sign PDF";
						}
					}
					if(pdf_sign_flag.equals("Y"))
					{
						nextStep="Send Mail";
					}
					if(email_sent_flag.equals("Y"))
					{
						nextStep="";	
						if(sap_approval_flag.equals(""))
						{
							nextStep="SAP/SUN Approval";
						}
					}
				}
				
			}
			else 
			{
				nextStep="Generate IRP";
			}
		}
		catch(Exception e)
		{
			new SystemErrorLogger().InsertErrorLogger(db_src_file_name, function_nm, e);
		}
		return nextStep;
	}
	
	public String getIrnFlag(String inv_no)
	{
		String function_nm="getIrnFlag()";
		String irn_flag="";
		try
		{
			String irn_no="";
			String queryString="SELECT IRN_NO "
					+ "FROM FMS_INVOICE_IRN_DTL "
					+ "WHERE COMPANY_CD=? AND INVOICE_NO=? ";
			stmt6=conn.prepareStatement(queryString);
			stmt6.setString(1, comp_cd);
			stmt6.setString(2, inv_no);
			rset6=stmt6.executeQuery();
			if(rset6.next())
			{
				irn_no=rset6.getString(1)==null?"":rset6.getString(1);
			}
			rset6.close();
			stmt6.close();
				
			irn_flag=irn_no.equals("")?"N":"Y";
		}
		catch(Exception e)
		{
			new SystemErrorLogger().InsertErrorLogger(db_src_file_name, function_nm, e);
		}
		return irn_flag;
	}
	
