			stmt6.setString(++ctn, plant_seq);
			stmt6.setString(++ctn, cont_type);
			stmt6.setString(++ctn, bu_seq);
			if(cont_type.equals("O") ||cont_type.equals("Q"))
			{
				stmt6.setString(++ctn, cargo_no);
			}
			stmt6.setString(++ctn, cont_no);
			stmt6.setString(++ctn, agmt_no);
			stmt6.setString(++ctn, company_cd);
			stmt6.setString(++ctn, counterparty_cd);
			stmt6.setString(++ctn, plant_seq);
			stmt6.setString(++ctn, cont_type);
			stmt6.setString(++ctn, bu_seq);
			if(cont_type.equals("O") ||cont_type.equals("Q"))
			{
				stmt6.setString(++ctn, cargo_no);
			}
