								VCONT_NO.add(""+VTEMP_CONT_NO.elementAt(i));
								VCONT_REV.add(""+VTEMP_CONT_REV.elementAt(i));
								VCONTRACT_TYPE.add(""+VTEMP_CONT_TYPE.elementAt(i));
								
								String deal_map = utilBean.NewDealMappingId(comp_cd, ""+VTEMP_COUNTERPARTY_CD.elementAt(i), ""+VTEMP_AGMT_NO.elementAt(i), ""+VTEMP_AGMT_REV.elementAt(i),
										""+VTEMP_CONT_NO.elementAt(i), ""+VTEMP_CONT_REV.elementAt(i), ""+VTEMP_CONT_TYPE.elementAt(i), ""+VTEMP_CARGO_NO.elementAt(i));
								VDISPLAY_DEAL_MAP.add(deal_map);
								VCONT_REF.add(VTEMP_CONT_REF.elementAt(i));
								VINVOICE_TYPE.add("Capacity [Buy]");	//cashflow type 
								VBILLING_FREQ_FLAG.add(billing_cycle);
								VBILLING_FREQ_NM.add(billing_freq_nm);
								VPERIOD_START_DT.add(temp_st_dt);
								VPERIOD_END_DT.add(temp_end_dt);
								VINVOICE_DT.add(temp_end_dt);
								VINVOICE_DUE_DT.add(utilBean.DueDateCalculation(conn,temp_end_dt, due_days,consider_due_dt_in,exclude_sat,comp_cd,holiday_state));
								VACC_COLOR.add("R");		//for tentative color R->Red
								VSETTELED_AMT.add(nf.format(gross_amt));
								VSETTELED_CURR.add("INR");
								/*VSETTELED_AMT.add(nf.format(accrual_amt));
								if((""+VTEMP_RATE_UNIT.elementAt(i)).equals("2"))
								{
									VSETTELED_CURR.add("USD");
								}
								else
								{
									VSETTELED_CURR.add("INR");
								}*/
								VDEAL_TYPE.add("Buy");
								VCONT_START_DT.add(""+VTEMP_CONT_START_DT.elementAt(i));
								VCONT_END_DT.add(""+VTEMP_CONT_END_DT.elementAt(i));
								VPLANT_SEQ_NO.add(""+VTEMP_PLANT_SEQ.elementAt(i));
								VBU_SEQ_NO.add(""+VTEMP_BU_SEQ.elementAt(i));
								VPLANT_ABBR.add(""+utilBean.getCounterpartyPlantABBR(conn, ""+VTEMP_COUNTERPARTY_CD.elementAt(i), comp_cd, ""+VTEMP_PLANT_SEQ.elementAt(i), "T"));
								VBU_ABBR.add(""+utilBean.getCounterpartyPlantABBR(conn, comp_cd, comp_cd, ""+VTEMP_BU_SEQ.elementAt(i), "B"));
								VDOC_STATUS.add("Not Prepared");
